package ru.lifegame.assets.domain.model.asset;

import java.util.List;

/**
 * Schema definition for sprite-atlas.json — the versioned atlas configuration
 * generated by the asset pipeline and consumed by the frontend SpriteController.
 * <p>
 * <b>Config Version: 1.0</b>
 * <p>
 * Structure:
 * <pre>
 * {
 *   "configVersion": "1.0",
 *   "revision": "latest",          // or "20260306-1" for pinned builds
 *   "character": "sam",
 *   "spriteWidth": 96,
 *   "spriteHeight": 80,
 *   "animations": {
 *     "idle": {
 *       "file": "idle_atlas.png",
 *       "layout": "grid",           // "grid" | "strip"
 *       "columns": 4,
 *       "rows": [
 *         {
 *           "rowIndex": 0,
 *           "condition": { "type": "time_of_day", "value": "morning" },
 *           "fps": 4,
 *           "loop": true
 *         },
 *         ...
 *       ],
 *       "defaultRow": 0
 *     },
 *     "walk": {
 *       "file": "walk_atlas.png",
 *       "layout": "strip",
 *       "columns": 6,
 *       "fps": 8,
 *       "loop": true
 *     }
 *   }
 * }
 * </pre>
 * <p>
 * <b>Versioning strategy:</b>
 * <ul>
 *   <li>{@code configVersion} — schema version (semver). Frontend checks compatibility.</li>
 *   <li>{@code revision} — build revision. "latest" (default) means always use
 *       the most recent generated output. Numbered revisions (e.g. "20260306-1")
 *       allow pinning to a specific asset build for reproducibility.</li>
 * </ul>
 * <p>
 * Frontend loads: {@code /assets/generated/characters/{name}/sprite-atlas.json?v=latest}
 * <p>
 * The ?v= param is for cache-busting; the actual revision is inside the JSON.
 *
 * @param configVersion schema version string ("1.0")
 * @param revision      build revision ("latest" or timestamp-based)
 * @param character     character identifier
 * @param spriteWidth   display width of one frame in CSS pixels
 * @param spriteHeight  display height of one frame in CSS pixels
 * @param animations    map of animation name → animation config
 */
public record AtlasConfigSchema(
        String configVersion,
        String revision,
        String character,
        int spriteWidth,
        int spriteHeight,
        java.util.Map<String, AnimationEntry> animations
) {
    public static final String CURRENT_VERSION = "1.0";
    public static final String LATEST_REVISION = "latest";

    /**
     * Single animation entry within the config.
     *
     * @param file       atlas PNG filename (relative to animations/ dir)
     * @param layout     "grid" or "strip"
     * @param columns    number of frame columns in the atlas
     * @param fps        playback fps (used for strip layout; grid rows override per-row)
     * @param loop       whether animation loops (used for strip; grid rows override)
     * @param rows       row definitions (only for grid layout)
     * @param defaultRow default row index (only for grid layout)
     */
    public record AnimationEntry(
            String file,
            String layout,
            int columns,
            int fps,
            boolean loop,
            List<RowDef> rows,
            int defaultRow
    ) {
        /** Strip constructor (no rows) */
        public AnimationEntry(String file, int columns, int fps, boolean loop) {
            this(file, "strip", columns, fps, loop, List.of(), 0);
        }
    }

    /**
     * Row definition for grid layouts.
     */
    public record RowDef(
            int rowIndex,
            Condition condition,
            int fps,
            boolean loop
    ) {}

    /**
     * Condition for selecting a row.
     */
    public record Condition(
            String type,
            String value
    ) {}
}
